\forall Seq seq;
\forall int from;
\forall int to;
\forall int idx;
    seqGet<[any]>(seqSub(seq, from, to)<<Trigger>>, idx)
  = \if(0 <= idx & idx < (to - from))
    \then(seqGet<[any]>(seq, idx + from))
    \else(seqGetOutside)

\forall Seq seq;
\forall int from;
\forall int to;
    seqLen(seqSub(seq, from, to)<<Trigger>>)
  = \if(from < to)\then(to - from)\else(0)
